def a(n):
    def update(x):
        k = len(x); new = [0]*k
        for i in range(k):
            w = [x[(i+d) % k] for d in range(-2, 3)]
            best = {0:0, 1:0}; cv, cl = w[0], 1; best[cv] = 1
            for j in range(1, 5):
                if w[j] == cv: cl += 1
                else: cv = w[j]; cl = 1
                best[cv] = max(best[cv], cl)
            if best[1] > best[0]: new[i] = 1
            elif best[0] > best[1]: new[i] = 0
            else: new[i] = x[i]
        return new
    count = 0
    for s in range(1 << n):
        x = [(s >> i) & 1 for i in range(n)]
        if x == update(x): count += 1
    return count
